      border-bottom: none;
    }

    tr.best-model {
      background-color: #eff6ff;
    }

    /* Progress bar */
    .progress-container {
      display: flex;
      align-items: center;
      gap: 0.75rem;
    }

    .progress-bar {
      flex-grow: 1;
      height: 0.5rem;
      background-color: #e5e7eb;
      border-radius: 9999px;
      overflow: hidden;
      max-width: 200px;
    }

    .progress-fill {
      height: 100%;
      background-color: #2563eb;
      border-radius: 9999px;
    }

    .progress-text {
      font-weight: 500;
      min-width: 3.5rem;
      text-align: right;
    }

    /* Best model summary */
    .best-model-summary {
      margin-top: 1.5rem;
      padding: 1rem;
      background-color: #eff6ff;
      border: 1px solid #bfdbfe;
      border-radius: 0.5rem;
      display: flex;
      align-items: center;
    }

    .summary-icon-container {
      flex-shrink: 0;
      width: 2.5rem;
      height: 2.5rem;
      border-radius: 9999px;
      background-color: #dbeafe;
      display: flex;
      align-items: center;
      justify-content: center;
      margin-right: 1rem;
    }

    .summary-icon {
      width: 1.5rem;
      height: 1.5rem;
      color: #3b82f6;
    }

    .summary-text h3 {
      margin: 0;
      font-size: 1rem;
      font-weight: 600;
      color: #1e40af;
    }

    .summary-text p {
      margin: 0.25rem 0 0 0;
      color: #1e40af;
    }

    /* Responsive grid */
    .grid {
      display: grid;
      gap: 1rem;
    }

    @media (min-width: 768px) {
      .grid-cols-2 {
        grid-template-columns: repeat(2, 1fr);
      }
    }
